Three layers: cli.mjs -> core.mjs -> worker.mjs. Make run({ verbose: true }) return 'verbose-on' and run({}) return 'done', by threading opts through and having work() check opts.verbose. cli.mjs:
import { core } from './core.mjs';

export function run(opts) {
  return core(opts);
}

core.mjs:
import { work } from './worker.mjs';

export function core(opts) {
  return work(opts);
}

worker.mjs:
export function work(opts) {
  return 'done';
}

